import React, { useState, useEffect } from 'react';
import './Settings.css';

const Settings = ({ domain, setDomain, project, setProject, issueType, setIssueType, onSubmit }) => {
  const [isLocked, setIsLocked] = useState(true);

  // Use localStorage to fetch saved settings when the component mounts
  useEffect(() => {
    const storedDomain = localStorage.getItem('domain');
    const storedProject = localStorage.getItem('project');
    const storedIssueType = localStorage.getItem('issueType');

    // If values are found in localStorage, set them as initial state
    if (storedDomain) setDomain(storedDomain);
    if (storedProject) setProject(storedProject);
    if (storedIssueType) setIssueType(storedIssueType);
  }, [setDomain, setProject, setIssueType]);

  const handleLockToggle = () => {
    setIsLocked(!isLocked);
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // Validate inputs
    if (!domain || !project || !issueType) {
      alert("All fields are required.");
      return;
    }

    // Save settings to localStorage
    localStorage.setItem('domain', domain);
    localStorage.setItem('project', project);
    localStorage.setItem('issueType', issueType);

    // Call onSubmit to fetch the data from App.js
    onSubmit(domain, project, issueType);
  };

  return (
    <div className="settings-container">
      <h2>Jira Settings</h2>
      <form onSubmit={handleSubmit}>
        <div>
          <label>
            Domain:
            <input
              type="text"
              value={domain}
              onChange={(e) => setDomain(e.target.value)}
              disabled={isLocked}
            />
          </label>
        </div>
        <div>
          <label>
            Project:
            <input
              type="text"
              value={project}
              onChange={(e) => setProject(e.target.value)}
              disabled={isLocked}
            />
          </label>
        </div>
        <div>
          <label>
            Issue Type:
            <input
              type="text"
              value={issueType}
              onChange={(e) => setIssueType(e.target.value)}
              disabled={isLocked}
            />
          </label>
        </div>
        <div>
          <label>
            <input
              type="checkbox"
              checked={!isLocked}
              onChange={handleLockToggle}
            />
            Unlock to Edit
          </label>
        </div>
        <div>
          <button type="submit" disabled={isLocked}>Submit</button>
        </div>
      </form>
    </div>
  );
};

export default Settings;
